CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_hr_off_member_aid() RETURNS trigger AS $BODY$
BEGIN
    --validate
  if coalesce(trim(both NEW.cancel_status)::text, '') = '' then NEW.cancel_status := '0';end if;
  if coalesce(trim(both NEW.post_status)::text, '') = '' then NEW.post_status := '0';end if;
  if (coalesce(OLD.official_no::text, '') = '' and (NEW.official_no IS NOT NULL AND NEW.official_no::text <> '') ) then
    if (pka.auto_entry) then 
        NEW.entry_id := current_setting('app.login_id', true);
        NEW.entry_date := statement_timestamp();
        NEW.entry_br := current_setting('app.login_br', true);
        NEW.entry_pc := pka_com_login.login_pc;
    end if;
  end if;

  if (coalesce(NEW.aid_amount::text, '') = '' or NEW.aid_amount = 0) and NEW.cancel_status <> '1' then
    CALL spa_dberror('จำนวนเงิน ช่วยเหลือเจ้าหน้าที่ ที่ได้รับต้องมากกว่าศูนย์');
  end if;
  --seq_no
  if coalesce(NEW.seq_no::text, '') = '' then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_hr_off_member_aid
    where (official_no = NEW.official_no);
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;

  if NEW.cancel_status = '1' then
    if coalesce(NEW.cancel_date::text, '') = '' then NEW.cancel_date := statement_timestamp();end if;
    if coalesce(NEW.cancel_id::text, '') = '' then NEW.cancel_id := current_setting('app.login_id', true);end if;
    if coalesce(NEW.cancel_br::text, '') = '' then NEW.cancel_br := current_setting('app.login_br', true);end if;
  end if;
RETURN NEW;
end
